1895 bool VectorCombine::foldBinopOfReductions(Instruction &I) {
1896   Instruction::BinaryOps BinOpOpc = cast<BinaryOperator>(&I)->getOpcode();
1897   Intrinsic::ID ReductionIID = getReductionForBinop(BinOpOpc);
1898   if (BinOpOpc == Instruction::Sub)
1899     ReductionIID = Intrinsic::vector_reduce_add;
1900   if (ReductionIID == Intrinsic::not_intrinsic)
1901     return false;
1902 
1903   if (!EnableFoldBinopOfReductions)
1904     return false;
1905 
1906   auto ReplaceValue = [&](Instruction &I, Value &V) { replaceValue(I, V); };
1907 
1908   // Reduce the number of reductions by folding a binop of a reduction and a
1909   // scalar (which might be another reduction) into a single reduction of a
1910   // vector binop. This leverages associativity and commutativity of the
1911   // binary operation (Add/Sub) to group reductions together.
1912   //
1913   // Examples:
1914   //   (Reduce(X) + Y) + Reduce(Z)  -> Reduce(X + Z) + Y
1915   //   (Reduce(X) - Y) - Reduce(Z)  -> Reduce(X - Z) - Y
1916   //   Reduce(Z) - (Reduce(X) + Y)  -> Reduce(Z - X) - Y
1917   if (auto *Op0 = dyn_cast<BinaryOperator>(I.getOperand(0))) {
1918     if (matchAssociativeReduction(I, BinOpOpc, ReductionIID, Builder, Op0,
1919                                   I.getOperand(1),
1920                                   /*ScalarReduceCIsLeft=*/false, ReplaceValue))
1921       return true;
1922   }
1923 
1924   if (auto *Op1 = dyn_cast<BinaryOperator>(I.getOperand(1))) {
1925     if (matchAssociativeReduction(I, BinOpOpc, ReductionIID, Builder, Op1,
1926                                   I.getOperand(0), /*ScalarReduceCIsLeft=*/true,
1927                                   ReplaceValue))
1928       return true;
1929   }
1930 
1931   Value *V0 = checkIntrinsicAndGetItsArgument(I.getOperand(0), ReductionIID);
1932   if (!V0)
1933     return false;
1934   Value *V1 = checkIntrinsicAndGetItsArgument(I.getOperand(1), ReductionIID);
1935   if (!V1)
1936     return false;
1937 
1938   auto *VTy = cast<VectorType>(V0->getType());
1939   if (V1->getType() != VTy)
1940     return false;
1941   const auto &II0 = *cast<IntrinsicInst>(I.getOperand(0));
1942   const auto &II1 = *cast<IntrinsicInst>(I.getOperand(1));
1943   unsigned ReductionOpc =
1944       getArithmeticReductionInstruction(II0.getIntrinsicID());
1945 
1946   InstructionCost OldCost = 0;
1947   InstructionCost NewCost = 0;
1948   InstructionCost CostOfRedOperand0 = 0;
1949   InstructionCost CostOfRed0 = 0;
1950   InstructionCost CostOfRedOperand1 = 0;
1951   InstructionCost CostOfRed1 = 0;
