1989 /// Helper class to indicate whether a vector index can be safely scalarized and
1990 /// if a freeze needs to be inserted.
1991 class ScalarizationResult {
1992   enum class StatusTy { Unsafe, Safe, SafeWithFreeze };
1993 
1994   StatusTy Status;
1995   Value *ToFreeze;
1996 
1997   ScalarizationResult(StatusTy Status, Value *ToFreeze = nullptr)
1998       : Status(Status), ToFreeze(ToFreeze) {}
1999 
2000 public:
2001   ScalarizationResult(const ScalarizationResult &Other) = default;
2002   ~ScalarizationResult() {
2003     assert(!ToFreeze && "freeze() not called with ToFreeze being set");
2004   }
2005 
2006   static ScalarizationResult unsafe() { return {StatusTy::Unsafe}; }
2007   static ScalarizationResult safe() { return {StatusTy::Safe}; }
2008   static ScalarizationResult safeWithFreeze(Value *ToFreeze) {
2009     return {StatusTy::SafeWithFreeze, ToFreeze};
2010   }
2011 
2012   /// Returns true if the index can be scalarize without requiring a freeze.
2013   bool isSafe() const { return Status == StatusTy::Safe; }
2014   /// Returns true if the index cannot be scalarized.
2015   bool isUnsafe() const { return Status == StatusTy::Unsafe; }
2016   /// Returns true if the index can be scalarize, but requires inserting a
2017   /// freeze.
2018   bool isSafeWithFreeze() const { return Status == StatusTy::SafeWithFreeze; }
2019 
2020   /// Reset the state of Unsafe and clear ToFreze if set.
2021   void discard() {
2022     ToFreeze = nullptr;
2023     Status = StatusTy::Unsafe;
2024   }
2025 
2026   /// Freeze the ToFreeze and update the use in \p User to use it.
2027   void freeze(IRBuilderBase &Builder, Instruction &UserI) {
2028     assert(isSafeWithFreeze() &&
2029            "should only be used when freezing is required");
2030     assert(is_contained(ToFreeze->users(), &UserI) &&
2031            "UserI must be a user of ToFreeze");
2032     IRBuilder<>::InsertPointGuard Guard(Builder);
2033     Builder.SetInsertPoint(cast<Instruction>(&UserI));
2034     Value *Frozen =
2035         Builder.CreateFreeze(ToFreeze, ToFreeze->getName() + ".frozen");
2036     for (Use &U : make_early_inc_range((UserI.operands())))
2037       if (U.get() == ToFreeze)
2038         U.set(Frozen);
2039 
2040     ToFreeze = nullptr;
2041   }
2042 };
