2045 /// Check if it is legal to scalarize a memory access to \p VecTy at index \p
2046 /// Idx. \p Idx must access a valid vector element.
2047 static ScalarizationResult canScalarizeAccess(VectorType *VecTy, Value *Idx,
2048                                               Instruction *CtxI,
2049                                               AssumptionCache &AC,
2050                                               const DominatorTree &DT) {
2051   // We do checks for both fixed vector types and scalable vector types.
2052   // This is the number of elements of fixed vector types,
2053   // or the minimum number of elements of scalable vector types.
2054   uint64_t NumElements = VecTy->getElementCount().getKnownMinValue();
2055   unsigned IntWidth = Idx->getType()->getScalarSizeInBits();
2056 
2057   if (auto *C = dyn_cast<ConstantInt>(Idx)) {
2058     if (C->getValue().ult(NumElements))
2059       return ScalarizationResult::safe();
2060     return ScalarizationResult::unsafe();
2061   }
2062 
2063   // Always unsafe if the index type can't handle all inbound values.
2064   if (!llvm::isUIntN(IntWidth, NumElements))
2065     return ScalarizationResult::unsafe();
2066 
2067   APInt Zero(IntWidth, 0);
2068   APInt MaxElts(IntWidth, NumElements);
2069   ConstantRange ValidIndices(Zero, MaxElts);
2070   ConstantRange IdxRange(IntWidth, true);
2071 
2072   if (isGuaranteedNotToBePoison(Idx, &AC)) {
2073     if (ValidIndices.contains(computeConstantRange(Idx, /* ForSigned */ false,
2074                                                    true, &AC, CtxI, &DT)))
2075       return ScalarizationResult::safe();
2076     return ScalarizationResult::unsafe();
2077   }
2078 
2079   // If the index may be poison, check if we can insert a freeze before the
2080   // range of the index is restricted.
2081   Value *IdxBase;
2082   ConstantInt *CI;
2083   if (match(Idx, m_And(m_Value(IdxBase), m_ConstantInt(CI)))) {
2084     IdxRange = IdxRange.binaryAnd(CI->getValue());
2085   } else if (match(Idx, m_URem(m_Value(IdxBase), m_ConstantInt(CI)))) {
2086     IdxRange = IdxRange.urem(CI->getValue());
2087   }
2088 
2089   if (ValidIndices.contains(IdxRange))
2090     return ScalarizationResult::safeWithFreeze(IdxBase);
2091   return ScalarizationResult::unsafe();
2092 }
