1313 Value *llvm::getOrderedReduction(IRBuilderBase &Builder, Value *Acc, Value *Src,
1314                                  unsigned Op, RecurKind RdxKind) {
1315   unsigned VF = cast<FixedVectorType>(Src->getType())->getNumElements();
