1317   // Extract and apply reduction ops in ascending order:
1318   // e.g. ((((Acc + Scl[0]) + Scl[1]) + Scl[2]) + ) ... + Scl[VF-1]
1319   Value *Result = Acc;
1320   for (unsigned ExtractIdx = 0; ExtractIdx != VF; ++ExtractIdx) {
1321     Value *Ext =
