1930 
1931   Value *V0 = checkIntrinsicAndGetItsArgument(I.getOperand(0), ReductionIID);
1932   if (!V0)
1933     return false;
1934   Value *V1 = checkIntrinsicAndGetItsArgument(I.getOperand(1), ReductionIID);
1935   if (!V1)
